int FindRoot()
{
	static int use[maxn],dis[maxn],fa[maxn];
	queue<int> q;
	int a,x=-1,y=-1;
	for(int i=1;i<=n;++i)
		if(col[i])
		{
			a=i;
			break;
		}
	q.push(a),use[a]=1,dis[a]=0;
	while(!q.empty())
	{
		int p=q.front();
		q.pop();
		for(int i=start[p];i;i=next[i])
			if(use[to[i]]!=1)
			{
				dis[to[i]]=dis[p]+len[i];
				q.push(to[i]);
				use[to[i]]=1;
				if(col[to[i]]&&(x==-1||dis[x]<dis[to[i]]))
					x=to[i];
			}
	}
	q.push(x),use[x]=2,dis[x]=0;
	while(!q.empty())
	{
		int p=q.front();
		q.pop();
		for(int i=start[p];i;i=next[i])
			if(use[to[i]]!=2)
			{
				dis[to[i]]=dis[p]+len[i];
				q.push(to[i]);
				use[to[i]]=2;
				if(col[to[i]]&&(y==-1||dis[y]<dis[to[i]]))
					y=to[i];
				fa[to[i]]=p;
			}
	}
	int minv=1<<30,id;
	for(int i=y;i!=x;i=fa[i])
	{
		int del=abs(dis[i]-(dis[y]-dis[i]));
		if(minv>del)
			minv=del,id=i;
	}
	return id;
