void DFS(int p)
{
	if(col[p])
		maxdep[p]=dep[p],cnt[p]=1;
	for(int i=start[p];i;i=next[i])
		if(to[i]!=father[p])
		{
			father[to[i]]=p;
			dep[to[i]]=dep[p]+len[i];
			pos[to[i]]=p==root?to[i]:pos[p];
			DFS(to[i]);
			if(maxdep[p]<maxdep[to[i]])
