				val=size[i];
			else
			{
				val=size[i];
				if(cnt[i]==cnt[pos[i]]&&maxdep[i]==maxdep[pos[i]])
				{
					if(maxdep[i]==max1&&s1==1)
						val+=size[root]-size[pos[i]];
					if(maxdep[i]==max1&&s1==2)
						val+=size[pos[i]==num1?num2:num1];
					if(maxdep[pos[i]]==max2&&s1==1&&s2==1&&max2)
						val+=size[num1];
				}
			}
			if(maxv<val)
				maxv=val,sum=1;
			else if(maxv==val)
				++sum;
		}
	printf("%d %d\n",maxv,sum);
}
int main()
{
	read();
	root=FindRoot();
	DFS(root);
	work();
	return 0;
}

