	{
		int u, w;
		halfEdge *next;
	};
	halfEdge adj_pool[MaxM * 2], *adj_tail;
	halfEdge *adj[MaxN + 1];

	int vFS, vFT;

	inline void adj_init()
	{
		adj_tail = adj_pool;
		for (int v = 1; v <= n; v++)
			adj[v] = NULL;
	}

	int tot_flows;
	int tot_flows_bak;
	int flow_bak[MaxM * 2];

	inline void flow_backup()
	{
		tot_flows_bak = tot_flows;
		int l = adj_tail - adj_pool;
		for (int i = 0; i < l; i++)
			flow_bak[i] = adj_pool[i].w;
	}
	inline void flow_recover()
	{
		tot_flows = tot_flows_bak;
		int l = adj_tail - adj_pool;
		for (int i = 0; i < l; i++)
			adj_pool[i].w = flow_bak[i];
	}

	inline halfEdge *oppo(halfEdge *e)
	{
		return adj_pool + ((e - adj_pool) ^ 1);
	}

	inline void addEdge(int v, int u, int w)
	{
		adj_tail->u = u, adj_tail->w = w, adj_tail->next = adj[v], adj[v] = adj_tail++;
		adj_tail->u = v, adj_tail->w = 0, adj_tail->next = adj[u], adj[u] = adj_tail++;
	}

	halfEdge *dfs_cur[MaxN + 1];
