	int dfs(int v, int delta)
	{
		if (v == vFT)
			return delta;
		int flow = 0;
		for (halfEdge *e = dfs_cur[v]; e; e = e->next)
			if (e->w > 0 && dist[v] == dist[e->u] + 1)
			{
				int d = dfs(e->u, min(delta - flow, e->w));
				flow += d;
				e->w -= d, oppo(e)->w += d;
				if (flow == delta)
				{
					dfs_cur[v] = e;
					return flow;
				}
			}
		if (flow == 0)
			dist[v] = n;
		return flow;
	}

	inline void calc_dist()
	{
		int q_n = 0;
		static int q[MaxN];

		for (int v = 1; v <= n; v++)
			dist[v] = n;

		dist[vFT] = 0, q[q_n++] = vFT;
		for (int i = 0; i < q_n; i++)
		{
			int v = q[i];
