#define Forr(i, a, b) for(int i = (a); i >= (int)(b); --i)

#define ML (1000000+5)
const LL P = 1000000007;

char rtmp[ML];
int TOT;
LL readtmp, nn, mm;

LL lread(){
    scanf("%s", rtmp+1);
    int len = strlen(rtmp+1);
    
    LL ret = 0ll; readtmp = 0;
    For(i, 1, len){
        ret = ret*10 + rtmp[i]-'0';
        readtmp = readtmp*10 + rtmp[i]-'0';
        ret %= P-1; readtmp %= P;
    }
    return ret;
}

LL Pow(LL na, LL anum){
    LL ret = 1;
    bool flag = anum==-2;
    if(anum < 0) anum = P-2;

    while(anum){
        if(anum&1) ret = (ret*na)%P;
        na = (na*na)%P; anum >>= 1;
    }

    if(flag) ret = ret*ret%P;
    return ret;
}

LL n, m, a, b, c, d;

LL CLine(LL na, LL anum){
    return ((Pow(na, anum+1)-1)*Pow(na-1, P-2)%P+P)%P;
}

