modint f[1<<16]; // topo orders
modint g[1<<16][17],h[1<<16][17];

bool no(int s,int t){
	// no s->t
	return (es[s]&t)==0;
}

modint Cdown(int n,int m){
	return fac[n]*ifac[n-m];
}
ull tt[23];

void work()
{
	n=read(),m=read(),k=read(); if(m==0) puts("1"),exit(0);
	For(i,1,m){
		int u=read(),v=read();
		--u,--v;
		e[u]|=(1<<v);
	}
	For(i,1,(1<<n)-1){
		int t=__lg(i&-i);
		es[i]=es[i^(1<<t)]|e[t];
	}
//	For(i,0,(1<<n)-1) cout<<es[i]<<" "; cout<<" es\n";
	f[0]=1;
	For(s,0,(1<<n)-1)
		For(i,0,n-1)
			if(!(s>>i&1) && no((1<<i),s)) f[s|(1<<i)]+=f[s];
