	g[0][0]=1;
	h[0][0]=1;
	For(s,1,(1<<n)-1){
		int u=__lg(s&-s);
		int c=__builtin_popcount(s);
		for(int t=s;t;t=(t-1)&s){
			if(t>>u&1){
				if(no(t,s^t) && no(s^t,t)){
					For(i,1,c) g[s][i]+=g[s^t][i-1]*f[t];
				}
			}
		}
		for(int t=s;t;t=(t-1)&s){
			if(no(s^t,t)){
				For(i,1,c)
					For(j,1,i)if(g[t][j].x && h[s^t][i-j].x){
						if(j&1) tt[i]+=1ull*g[t][j].x*h[s^t][i-j].x;
						else tt[i]+=1ull*(mod-g[t][j].x)*h[s^t][i-j].x;
					}
				For(i,1,c) h[s][i]+=tt[i]%mod,tt[i]=0;
			}
		}
	}
//	For(s,0,(1<<n)-1) For(i,0,n) if(g[i][s].x) cout<<"g "<<i<<" "<<s<<" "<<g[i][s].x<<"\n";
//	For(s,0,(1<<n)-1) For(i,0,n) if(h[i][s].x) cout<<"h "<<i<<" "<<s<<" "<<h[i][s].x<<"\n";
	initC(n+k+50);
	modint res=0;
	For(i,1,n){
//		cout<<"hi "<<i<<" "<<h[i][(1<<n)-1].x<<"\n";
		modint coe=0;
		For(j,0,i-1)coe+=C(i-1,j)*sign(j)*Cdown(i-j+k,k);
		res+=coe*fac[i]*h[(1<<n)-1][i];
	}
	res*=ifac[n+k];
	cout<<res.x<<"\n";
}

