                    else solve(1), solve(2);
                }
                if(c1 > s1.size() + l && s[i] == '0') ok = false;
                if(c2 > s2.size() && s[i] == '1') ok = false;
            }
            if(n & 1){
                if(!path.empty()) ans.push_back(path.back());
                else if(c1 < s1.size()) ans.push_back(s1.back());
                else ans.push_back(s2.back());
            }
            if(ok){
                cout << "YES\n";
                for(int x: ans) cout << x << ' ';
                cout << '\n';
            }
            else cout << "NO\n";
        }
        return;
    }
} // namespace Main
